import React, { useState } from 'react';

const Step1 = ({ formData, handleChange }) => (<p className='info'>Step 1 - This is a sample</p>);
const Step2 = ({ formData, handleChange }) => (<p className='warning'>Step 2 - This is a sample</p>);
const Step3 = ({ formData, handleChange }) => (<p className='success'>Step 3 - This is a sample</p>);

const FormVariations = () => {
    const [currentStep, setCurrentStep] = useState(1);
    const [formData, setFormData] = useState({});

    const steps = [{ label: 'Account Info', component: Step1 }, { label: 'Personal Details', component: Step2 }, { label: 'Finish', component: Step3 },];
    const CurrentComponent = steps[currentStep - 1].component;
    const totalSteps = steps.length;

    const handleChange = (e) => { const { name, value } = e.target; setFormData(prev => ({ ...prev, [name]: value })); };
    const nextStep = () => { if (currentStep < totalSteps) { setCurrentStep(currentStep + 1); } };
    const prevStep = () => { if (currentStep > 1) { setCurrentStep(currentStep - 1); } };

    /* const progressPercentage = ((currentStep - 1) / (totalSteps - 1)) * 100; */
    const progressPercentage = (100 / totalSteps) * currentStep;

    const handleSubmit = () => {
        alert('Form Submitted!\n' + JSON.stringify(formData, null, 2));
        setFormData({}); setCurrentStep(1);
    };

    return (
        <div className='admin-pager'>
            <header className='admin-pager-head'>
                <div className='admin-pager-title'> <span><h2>Form Variations</h2><p>Multi-Step Form Layouts</p></span>  </div>
            </header>

            <div className='admin-pager-body'>
                <div className='flex-column'>
                    <div className='w5'>
                        <div className='pagelet form-steps-case'>
                            <div className='pagelet-head'>
                                <div className='form-steps-wrap'>
                                    <div className='form-steps-bar'><em style={{ width: `${progressPercentage}%` }}></em></div>
                                    <ul className='form-steps'>
                                        {steps.map((step, i) => (<li key={i} className={`form-step ${i + 1 < currentStep ? 'completed' : ''} ${i + 1 === currentStep ? 'active' : ''}`} > <h1>{i + 1}</h1> <p>{step.label}</p> </li>))}
                                    </ul>
                                </div>
                            </div>
                            <div className='pagelet-head'>
                                <div className='form-steps-wrap step-dotted'>
                                    <div className='form-steps-bar'><em style={{ width: `${progressPercentage}%` }}></em></div>
                                    <ul className='form-steps'>
                                        {steps.map((step, i) => (<li key={i} className={`form-step ${i + 1 < currentStep ? 'completed' : ''} ${i + 1 === currentStep ? 'active' : ''}`} > <h1>{ }</h1> </li>))}
                                    </ul>
                                </div>
                            </div>
                            <div className='pagelet-in flex-row'>
                                <h4>BASIC</h4>
                                <CurrentComponent formData={formData} handleChange={handleChange} />
                            </div>
                            <div className='pagelet-foot'>
                                {currentStep > 1 && (<button className='button btn-step-prev btn-outlined' onClick={prevStep} >Previous</button>)}
                                {currentStep < totalSteps ? (<button className='button' onClick={nextStep} >Next</button>) : (<button className='button' onClick={handleSubmit} >Finish</button>)}
                            </div>
                        </div>
                    </div>
                    <div className='w5'>
                        <div className='pagelet form-steps-case'>
                            <div className='pagelet-head'>
                                <div className='form-steps-wrap'>
                                    <div className='form-steps-bar'><em style={{ width: `${progressPercentage}%` }}></em></div>
                                    <ul className='form-steps'>
                                        {steps.map((step, i) => (<li key={i} className={`form-step focus ${i + 1 < currentStep ? 'completed' : ''} ${i + 1 === currentStep ? 'active' : ''}`} > <h1>{i + 1}</h1> <p>{step.label}</p> </li>))}
                                    </ul>
                                </div>
                            </div>
                            <div className='pagelet-head'>
                                <div className='form-steps-wrap step-dotted'>
                                    <div className='form-steps-bar'><em style={{ width: `${progressPercentage}%` }}></em></div>
                                    <ul className='form-steps'>
                                        {steps.map((step, i) => (<li key={i} className={`form-step focus ${i + 1 < currentStep ? 'completed' : ''} ${i + 1 === currentStep ? 'active' : ''}`} > <h1>{ }</h1> </li>))}
                                    </ul>
                                </div>
                            </div>
                            <div className='pagelet-in flex-row'>
                                <h4>FOCUS ON ACTIVE</h4>
                                <CurrentComponent formData={formData} handleChange={handleChange} />
                            </div>
                            <div className='pagelet-foot'>
                                {currentStep > 1 && (<button className='button btn-step-prev btn-outlined' onClick={prevStep} >Previous</button>)}
                                {currentStep < totalSteps ? (<button className='button' onClick={nextStep} >Next</button>) : (<button className='button' onClick={handleSubmit} >Finish</button>)}
                            </div>
                        </div>
                    </div>
                </div>

                <div className='flex-column'>
                    <div className='w5'>
                        <div className='pagelet form-steps-case'>
                            <div className='pagelet-head'>
                                <div className='form-steps-wrap default'>
                                    <div className='form-steps-bar'></div>
                                    <ul className='form-steps'>
                                        {steps.map((step, i) => (
                                            <li key={i} className={`form-step ${i + 1 === currentStep ? 'active' : ''} ${i + 1 < currentStep ? 'completed' : ''}`} >
                                                <h1 onClick={() => setCurrentStep(i + 1)} style={{ cursor: 'pointer' }}>{i + 1}</h1>
                                                <p>{step.label}</p>
                                            </li>))}
                                    </ul>
                                </div>
                            </div>
                            <div className='pagelet-head'>
                                <div className='form-steps-wrap default step-dotted'>
                                    <div className='form-steps-bar'></div>
                                    <ul className='form-steps'>
                                        {steps.map((step, i) => (
                                            <li key={i} className={`form-step focus ${i + 1 === currentStep ? 'active' : ''} ${i + 1 < currentStep ? 'completed' : ''}`} >
                                                <h1>{ }</h1>
                                            </li>))}
                                    </ul>
                                </div>
                            </div>
                            <div className='pagelet-in flex-row'>
                                <h4>DEFAULT</h4>
                                <CurrentComponent formData={formData} handleChange={handleChange} />
                            </div>
                            <div className='pagelet-foot'>
                                {currentStep > 1 && (<button className='button btn-step-prev btn-outlined' onClick={prevStep} >Previous</button>)}
                                {currentStep < totalSteps ? (<button className='button' onClick={nextStep} >Next</button>) : (<button className='button' onClick={handleSubmit} >Finish</button>)}
                            </div>
                        </div>
                    </div>
                    <div className='w5'>
                        <div className='pagelet form-steps-case'>
                            <div className='pagelet-in flex-row'>
                                <h4>GRID</h4>
                                <div className='flex-column'>
                                    <div className='w4'>
                                        <div className='form-steps-wrap horizontal'>
                                            <ul className='form-steps'>
                                                {steps.map((step, i) => (
                                                    <li key={i} className={`form-step ${i + 1 === currentStep ? 'active' : ''} ${i + 1 < currentStep ? 'completed' : ''}`} onClick={() => { setCurrentStep(i + 1) }} >
                                                        <h1>{i + 1}</h1>
                                                        <p>{step.label}</p>
                                                    </li>))}
                                            </ul>
                                        </div>
                                    </div>
                                    <div className='w6'><CurrentComponent formData={formData} handleChange={handleChange} /></div>
                                </div>
                            </div>
                            <div className='pagelet-foot'>
                                {currentStep > 1 && (<button className='button btn-step-prev btn-outlined' onClick={prevStep} >Previous</button>)}
                                {currentStep < totalSteps ? (<button className='button' onClick={nextStep} >Next</button>) : (<button className='button' onClick={handleSubmit} >Finish</button>)}
                            </div>
                        </div>
                    </div>
                </div>
            </div>



            <div className='flex-case'>


            </div>

        </div>);

};
export default FormVariations;